async def seed_database(db):
    """Seed the database with all equipment, drills, and training data."""
    import logging
    logger = logging.getLogger(__name__)

    # Check if already seeded
    count = await db.equipment.count_documents({})
    if count > 0:
        # Re-seed prices if new ones were added
        price_count = await db.equipment_prices.count_documents({})
        if price_count < len(EQUIPMENT_PRICES):
            await db.equipment_prices.delete_many({})
            await db.equipment_prices.insert_many(EQUIPMENT_PRICES)
            await db.equipment_prices.create_index("product_id")
            logger.info(f"Re-seeded {len(EQUIPMENT_PRICES)} price entries (was {price_count})")
        else:
            logger.info("Database already seeded. Skipping.")
        return

    logger.info("Seeding database...")

    # Seed equipment
    all_equipment = RACKETS + SHOES + OTHER_EQUIPMENT
    if all_equipment:
        await db.equipment.insert_many(all_equipment)
        logger.info(f"Seeded {len(all_equipment)} equipment items")

    # Seed prices
    if EQUIPMENT_PRICES:
        await db.equipment_prices.insert_many(EQUIPMENT_PRICES)
        logger.info(f"Seeded {len(EQUIPMENT_PRICES)} price entries")

    # Seed drills
    if DRILLS:
        await db.drills.insert_many(DRILLS)
        logger.info(f"Seeded {len(DRILLS)} drills")

    # Seed drill videos
    if DRILL_VIDEOS:
        await db.drill_videos.insert_many(DRILL_VIDEOS)
        logger.info(f"Seeded {len(DRILL_VIDEOS)} drill videos")

    # Seed training plans
    for level, plan in TRAINING_PLANS.items():
        await db.training_plans.insert_one(plan)
    logger.info(f"Seeded {len(TRAINING_PLANS)} training plans")

    # Create indexes
    await db.equipment.create_index("id", unique=True)
    await db.equipment.create_index("category")
    await db.equipment.create_index("brand")
    await db.drills.create_index("id", unique=True)
    await db.drills.create_index("skill_focus")
    await db.drills.create_index("difficulty")
    await db.equipment_prices.create_index("product_id")
    await db.drill_videos.create_index("drill_id")
    await db.users.create_index("phone", unique=True)
    await db.player_profiles.create_index("user_id", unique=True)
    await db.training_progress.create_index([("user_id", 1), ("plan_id", 1), ("day", 1)])

    logger.info("Database seeding complete!")
